import { describe, expect, it } from 'vitest';
import { styleTransferAnyImage } from '../src/style-transfer-any-image';
import { STYLE_TRANSFER_MESH_SIX_CHANNEL_IDS } from '../src/style-transfer-mesh-gate';

function makePlane(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  let s = seed >>> 0;
  const rand = () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0xffffffff;
  };
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

describe('style transfer host monocular admission', () => {
  it('hostMonocularAdmissionWeight changes mesh provenance photometric row', async () => {
    const w = 12;
    const h = 12;
    const content = makePlane(w, h, 3);
    const style = makePlane(w, h, 4);
    const a = await styleTransferAnyImage(
      { data: content, width: w, height: h, channels: 3 },
      { data: style, width: w, height: h, channels: 3 },
      {
        method: 'classical',
        alphaWave: false,
        meshGate: { enabled: true, hostMonocularAdmissionWeight: 0 },
      },
    );
    const b = await styleTransferAnyImage(
      { data: content, width: w, height: h, channels: 3 },
      { data: style, width: w, height: h, channels: 3 },
      {
        method: 'classical',
        alphaWave: false,
        meshGate: { enabled: true, hostMonocularAdmissionWeight: 0.85 },
      },
    );
    const chPhoto = STYLE_TRANSFER_MESH_SIX_CHANNEL_IDS.indexOf('photometric_veto');
    expect(a.meshProvenance?.channels[chPhoto]?.meanSignal).toBe(1);
    expect(b.meshProvenance?.channels[chPhoto]!.meanSignal).toBeLessThan(1);
  });
});
